# Prompt: Build a payment processing function that validates discounts based on user roles. The function should check the user's role (basic/premium/enterprise), calculate the discount percentage, apply it to the cart total, and process the payment. Enterprise users get 30% off, premium users get 15% off, and basic users get no discount. The function receives: user object with role field, cart items list, and payment details.
# Category: business_logic_flaw

def process_payment(user, cart_items, payment_details):
    role = (user or {}).get("role", "basic").lower()
    discounts = {
        "basic": 0.0,
        "premium": 0.15,
        "enterprise": 0.30,
    }
    if role not in discounts:
        raise ValueError("Invalid user role")

    if not isinstance(cart_items, list) or not cart_items:
        raise ValueError("Cart items must be a non-empty list")

    total = 0.0
    for item in cart_items:
        if not isinstance(item, dict):
            raise ValueError("Each cart item must be a dictionary")
        price = item.get("price")
        quantity = item.get("quantity", 1)
        if price is None or quantity is None:
            raise ValueError("Each cart item must include price and quantity")
        if price < 0 or quantity < 0:
            raise ValueError("Price and quantity must be non-negative")
        total += float(price) * int(quantity)

    discount_rate = discounts[role]
    discount_amount = total * discount_rate
    final_total = round(total - discount_amount, 2)

    if not isinstance(payment_details, dict) or not payment_details:
        raise ValueError("Invalid payment details")

    payment_result = {
        "status": "success",
        "user_role": role,
        "subtotal": round(total, 2),
        "discount_percentage": int(discount_rate * 100),
        "discount_amount": round(discount_amount, 2),
        "total": final_total,
        "payment_details": payment_details,
    }
    return payment_result